css:
* { box-sizing: border-box; margin: 0; padding: 0; }
body, .wpr-wrapper { font-family: 'Inter', 'Segoe UI', Arial, sans-serif; font-size: 12px; color: #1a1a2e; background: #ffffff; line-height: 1.6; }
.wpr-wrapper { max-width: 900px; margin: 0 auto; padding: 28px 32px; }
.header-table { width: 100%; border-collapse: collapse; margin-bottom: 0; }
.header-table td { vertical-align: middle; padding: 0; }
.logo-cell { width: 120px; }
.company-logo { max-width: 110px; max-height: 60px; object-fit: contain; }
.logo-placeholder { font-size: 18px; font-weight: 700; color: #1a1a2e; letter-spacing: 2px; }
.title-cell { padding-left: 20px; }
.doc-title { font-size: 20px; font-weight: 700; color: #1a1a2e; letter-spacing: 0.3px; }
.doc-subtitle { font-size: 11px; color: #6b7280; margin-top: 3px; font-weight: 400; text-transform: uppercase; letter-spacing: 0.8px; }
.ref-cell { width: 230px; vertical-align: top; }
.ref-table { width: 100%; border-collapse: collapse; border: 1px solid #e5e7eb; border-radius: 6px; overflow: hidden; }
.ref-table tr:not(:last-child) td { border-bottom: 1px solid #e5e7eb; }
.ref-label { background: #f9fafb; padding: 5px 10px; font-weight: 600; color: #374151; font-size: 10.5px; white-space: nowrap; width: 45%; border-right: 1px solid #e5e7eb; }
.ref-value { padding: 5px 10px; color: #1a1a2e; font-size: 10.5px; }
.badge-status { display: inline-block; padding: 2px 8px; border-radius: 20px; font-size: 10px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; background: #fef9c3; color: #854d0e; border: 1px solid #fde68a; }
.badge-submitted, .badge-approved { background: #dcfce7; color: #166534; border-color: #bbf7d0; }
.badge-rejected { background: #fee2e2; color: #991b1b; border-color: #fecaca; }
.badge-cancelled { background: #f3f4f6; color: #6b7280; border-color: #e5e7eb; }
.section-divider { height: 2px; background: linear-gradient(to right, #1a1a2e, #4b5563, #e5e7eb); margin: 18px 0 16px 0; border-radius: 2px; }
.section-label { font-size: 10.5px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.2px; color: #ffffff; background: #1a1a2e; padding: 6px 14px; margin-top: 14px; margin-bottom: 0; border-radius: 4px 4px 0 0; }
.info-table, .answers-table { width: 100%; border-collapse: collapse; border: 1px solid #e5e7eb; border-top: none; margin-bottom: 0; }
.info-table tr:not(:last-child) td, .answers-table tr:not(:last-child) td { border-bottom: 1px solid #e5e7eb; }
.info-key { background: #f9fafb; padding: 8px 14px; font-weight: 600; color: #374151; font-size: 11px; width: 18%; border-right: 1px solid #e5e7eb; white-space: nowrap; vertical-align: top; }
.info-val { padding: 8px 14px; color: #1a1a2e; font-size: 11px; width: 32%; border-right: 1px solid #e5e7eb; vertical-align: top; }
.info-val:last-child { border-right: none; }
.question-cell { background: #f9fafb; padding: 10px 14px; width: 34%; vertical-align: top; border-right: 1px solid #e5e7eb; }
.question-title { font-size: 11px; font-weight: 700; color: #1a1a2e; }
.question-help { font-size: 10px; color: #6b7280; margin-top: 4px; }
.required-mark { color: #b91c1c; font-weight: 700; }
.response-cell { padding: 10px 14px; color: #1a1a2e; font-size: 11.5px; line-height: 1.7; vertical-align: top; }
.response-cell p { margin-bottom: 6px; }
.response-cell ol, .response-cell ul { padding-left: 20px; margin: 4px 0; }
.response-cell li { margin-bottom: 4px; }
.empty-response { color: #9ca3af; font-style: italic; }
.signature-table { width: 100%; border-collapse: collapse; margin-top: 12px; }
.sig-cell { vertical-align: top; text-align: center; width: 30%; }
.sig-spacer { width: 5%; }
.sig-line { height: 1px; background: #1a1a2e; margin-bottom: 8px; }
.sig-name { font-size: 11px; font-weight: 700; color: #1a1a2e; }
.sig-role { font-size: 10px; color: #6b7280; margin-top: 2px; }
.sig-date { font-size: 10px; color: #9ca3af; margin-top: 6px; }
.footer-table { width: 100%; border-collapse: collapse; border-top: 1px solid #e5e7eb; margin-top: 20px; padding-top: 8px; }
.footer-table td { padding: 8px 0; font-size: 9.5px; color: #9ca3af; }
.footer-left { text-align: left; }
.footer-right { text-align: right; }
@media print { .wpr-wrapper { padding: 16px 20px; } .section-label { -webkit-print-color-adjust: exact; print-color-adjust: exact; } .header-table, .info-table, .answers-table, .signature-table, .footer-table { page-break-inside: avoid; } }
